var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니! 봤죠? 이번에는 저 혼자 해냈어요!","JPN":"リタお姉ちゃん！　見ました？　一人でやっつけたんですよ！","ENG":"Rita! Did you see that? I pulled it off all by myself this time!","TWN":"姐姐！看到了嗎？這次我自己做到了！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 말 안 듣고 제멋대로 굴더니 조금은 실력이 생겼네. 잘했어.","JPN":"そうだな。言うことも聞かずにいつも勝手に動き回ってたおかげで、少しは実力がついたんじゃないか。よくやった。","ENG":"Yeah, I saw. So you managed to improve a little, after being nothing but a troublemaker. That was good work back there.","TWN":"嗯。不聽話任性妄為，倒是練出了點實力。做得很好。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗! 방금 칭찬이었죠?!","JPN":"お！　今のは褒め言葉ですね！？","ENG":"Ooh! Was that a compliment just now?","TWN":"啊！剛剛那是稱讚吧？！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......아니. 나처럼 환청이라도 들었나 보지.","JPN":"……違う。私みたいに幻聴でも聞こえてるのか？","ENG":"No. Maybe you're hearing things. Just like me...","TWN":"……不是，你可能像我一樣出現幻聽了吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럴 리 없어요! 분명히 제 귀로 똑똑히 들었는걸요!","JPN":"そんなはずないです！　確かに聞こえましたよ？","ENG":"But that can't be! I could have sworn I heard you say it!","TWN":"不可能！我明明聽得清清楚楚！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"끈질기긴. 마음대로 생각해.","JPN":"しつこいな。勝手に言ってろ。","ENG":"You don't give up, do you? Think whatever you’d like.","TWN":"真煩，隨便你怎麼想。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗, 리타 언니! 같이 가요!","JPN":"あっ。リタお姉ちゃん！　置いていかないでくださいよ！","ENG":"Oh, Rita! Wait for me!","TWN":"啊！麗塔姐姐！一起走嘛！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으아......","JPN":"うわっ……","ENG":"Whoa...","TWN":"呃啊……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"여기가 관제실이군. 걱정한 것보단 상태가 양호한데.","JPN":"ここが管制室か。予想していたより状態は良好だな。","ENG":"This must be the control room. It's in better shape than I thought.","TWN":"這裡就是控制室，狀態比想像的要好。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"이렇게 망가졌는데도요?","JPN":"こんな壊れた状態なのに？","ENG":"But it's a wreck!","TWN":"都破成這樣了還好？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"밀거래를 하다 보면 알게 되지. 전쟁 전후에 생산된 기종들은 투박하긴 해도 그만큼 튼튼해.","JPN":"密売をしている人間にはわかるんだ。戦争前後に生産された機種は見た目はダサいが、その分頑丈だ。","ENG":"It's something you learn from dealing in the black market. Equipment made during the war was built to be as rugged as it looks.","TWN":"做過走私的都知道。戰爭前後生產的機種，雖然粗糙，但卻相當結實。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 정도로 보존되어 있다면 수리는 그렇게 어렵지 않아.","JPN":"この保存状態なら、修理はそう難しくないだろう。","ENG":"In this state, it should be good to go with a little repair.","TWN":"保存到這個程度，修理起來並不難。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, CRF가 거의 바닥났잖아요. 손으로 하려면 며칠 밤을 꼬박 새도 모자랄 거예요.","JPN":"でもリタお姉ちゃんはCRFがほぼ底をついているから、直接直すには数日徹夜しても終わらないんじゃ……","ENG":"But you're almost out of CRF, Rita. It'll take days to repair manually.","TWN":"姐姐，CRF已經沒剩下多少了。親自修理的話，幾天幾夜都不夠。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"안심해, 꼬맹이.","JPN":"安心しろ、ガキ。","ENG":"Don't worry, kid.","TWN":"放心，小鬼。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"오메르타를 불러낼 수는 없지만...... 이런 작업을 할 만큼은 남겨 뒀어.","JPN":"オメルタは呼び出せないけど……これぐらいの作業ができる力は残しておいた。","ENG":"I may not be able to summon Omerta... but I saved up enough CRF for this sort of work.","TWN":"雖然沒法召喚奧梅爾塔……但做這些工作沒有問題。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말요?!","JPN":"本当ですか！？","ENG":"Really?!","TWN":"真的？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 덕분에 꽤나 고생했지만 손 놓고 구경하는 일은 피한 셈이지.","JPN":"そう。おかげでかなり苦労はしたけど、指をくわえて見物するのだけは避けたかったからな。","ENG":"Yeah. It made the long walk suck that much more, but at least I won't have to just sit back and watch.","TWN":"嗯。雖然托你的福很辛苦，但也不能袖手旁觀。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니는 처음부터 다 계획이 있었네요! 전 그냥 아무 생각 없이 온 건데!","JPN":"リタお姉ちゃんは最初からちゃんと計画していたんですね！　私は何も考えずに来たのに！","ENG":"So you had a plan all along! I just came along without giving much thought!","TWN":"原來姐姐一開始就全都計畫好了！我什麼都沒想就來了！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"엉겨붙지 말고 좀 떨어져.","JPN":"くっつくな、少し離れてろ。","ENG":"Now give me some space, will you?","TWN":"別黏著我了，離遠點。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌, 분석은 얼마나 걸리겠어?","JPN":"ホライズン、分析はどれぐらいかかる？","ENG":"How long will it take to analyze the damage, Horizon?","TWN":"地平線，分析需要多久？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타의 말대로 내부 구조는 유지보수를 위해 단순한 편입니다. 오래 걸리진 않겠군요.","JPN":"リタの言うとおり、内部構造はメンテナンスのために単純な仕組みです。長くはかからないでしょう。","ENG":"As you suggested, the internal structure is relatively simple enough. It shouldn't take long.","TWN":"如你所言，為了維護修理，內部結構很簡單。應該不會花太長時間。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"문제는 연산장치를 비롯한 몇 가지 정밀 부품들입니다.","JPN":"問題は演算装置を含めた、いくつかの精密部品です。","ENG":"The only problem is the few sophisticated components like the computation device.","TWN":"問題是包括演算裝置在內的幾個精密零件。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"지금의 리타에게 이런 정밀 작업은 무리입니다. 능력을 제어할 CRF가 부족하니까요.","JPN":"今のリタにこのような精密作業は無理です。能力を制御するCRFが足りません。","ENG":"Such a meticulous task may place too much strain on you in your current condition. You simply don't have enough CRF to control the process.","TWN":"對現在的麗塔來說，這種精密作業太吃力了。因為控制你能力的CRF不足。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럼 어떡하면 돼요?","JPN":"それじゃあ、どうすればいいですか？","ENG":"Then what should we do?","TWN":"那怎麼辦？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"놀라지 마. 마침 우리 중에 비슷한 부품들을 가진 녀석이 있으니까.","JPN":"驚くな。ちょうど私たちの中に似た部品を持っている奴がいるだろ。","ENG":"Don't freak out just yet. It just so happens one of us has a few spares we could use.","TWN":"別害怕，正好我們中間有帶著類似零件的傢伙。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"부품을 가진 사람이라면......","JPN":"部品を持っている人って……","ENG":"Spares? You mean...","TWN":"帶著零件的人……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌 대표님?","JPN":"ホライズン代表？","ENG":"The Boss?","TWN":"地平線BOSS？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그렇습니다. 접니다.","JPN":"はい、私です。","ENG":"Precisely. They're inside me.","TWN":"是的，就是我。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"안 돼요, 대표님! 부품을 빼면 죽을 거예요!","JPN":"いけません、代表！　部品を外したら死んじゃいます！","ENG":"No, Boss! You'll die if we take them out!","TWN":"不行，BOSS！拿走零件你就死了！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"안 죽어.","JPN":"死なない。","ENG":"She won't die.","TWN":"死不了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"안 죽습니다.","JPN":"死にません。","ENG":"I won't die.","TWN":"不會死的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"기억 회로만 챙기면 돼. 본체는 어차피 정비 중이니까.","JPN":"記憶回路さえ確保しておけばいいんだよ。本体はどうせ整備中だから。","ENG":"We can just hold on to her memory unit. Her original body is undergoing repairs anyway.","TWN":"保留記憶回路就行，反正主機正在維修。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그...... 그렇구나...... 전 부품을 빼면 대표님이 죽는 줄로만 알았어요.","JPN":"そ……そうなんだ……部品を取り外したら代表が死んじゃうんじゃないかと思ってました。","ENG":"Oh... I see... I thought taking parts from you would kill you.","TWN":"這……這樣啊……我以為取下零件BOSS就死了呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"기억 회로를 못 찾으면 비슷한 상태가 되겠죠.","JPN":"記憶回路を回収できなければ似たような状態になるでしょう。","ENG":"Without the memory unit, I suppose I would undergo something similar to what you call death.","TWN":"如果找不到記憶回路，就差不多是那個狀態。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"하지만 대시, 당신 말대로 포기는 언제든 할 수 있습니다.","JPN":"しかしダッシュ、あなたの言うとおり諦めることはいつでもできます。","ENG":"But like you said, Dash, we can always give up when we feel like it.","TWN":"但是黛西，如你所說，放棄隨時都可以。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그러니 지금은 수단 방법 가리지 말고 노력해 봅시다.","JPN":"だから今は手段を選ばずに、努力してみましょう。","ENG":"For now, we'll just have to try whatever we can.","TWN":"所以現在要想盡一切辦法努力看看。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹!","JPN":"はいっ！","ENG":"Oki!","TWN":"是！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"대표님 훈시가 끝났으면 어서 돕도록 해. 호라이즌.","JPN":"代表の訓示が終わったらならさっさと手伝え、ホライズン。","ENG":"If you're done lecturing like an old fart, get started, Horizon.","TWN":"BOSS訓示的話已經結束的話，快點幫忙吧。地平線。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......더 늦으면 위험해질 것 같으니까.","JPN":"……これ以上遅れると危ないからな。","ENG":"I don't think we can afford to delay any longer.","TWN":"……再晚就危險了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};